(window.webpackJsonp=window.webpackJsonp||[]).push([[382],{1009:function(n,r){n.exports="\x3c!-- \r\ntitle: 23-JS函数\r\nsort: \r\n--\x3e \r\n# JS函数\r\n\r\n## 传参\r\n\r\n> `arguments`是包含所有传入参数的数组。\r\n\r\n```js\r\n// 使用多个变量\r\nfunction add() {\r\n    var sum = 0;\r\n    for (var i = 0, j = arguments.length; i < j; i++) {\r\n        sum += arguments[i];\r\n    }\r\n    return sum;\r\n}\r\n\r\nadd(2, 3, 4, 5); // 14\r\n\r\n// 或使用剩余参数操作符\r\nfunction avg(...args) {\r\n  var sum = 0;\r\n  for (let value of args) {\r\n    sum += value;\r\n  }\r\n  return sum / args.length;\r\n}\r\n\r\navg(2, 3, 4, 5); // 3.5\r\n```\r\n\r\n## 内部函数\r\n\r\n```js\r\nfunction parentFunc() {\r\n  var a = 1;\r\n\r\n  function nestedFunc() {\r\n    var b = 4; // parentFunc 无法访问 b\r\n    return a + b;\r\n  }\r\n  return nestedFunc(); // 5\r\n}\r\n```\r\n\r\n## "}}]);